class Solution {
public:
    string smallestSubsequence(string s) {
        stack<char> st;
        vector<bool> seen(26, false);
        for (char c : s) {
            if (st.empty() || c < st.top()) {
                st.push(c);
            } else if (seen[c - 'a']) {
                continue;
            } else {
                while (!st.empty() && st.top() > c) {
                    seen[st.top() - 'a'] = false;
                    st.pop();
                }
                st.push(c);
            }
            seen[c - 'a'] = true;
        }
        string res = "";
        while (!st.empty()) {
            res += st.top();
            st.pop();
        }
        reverse(res.begin(), res.end());
        return res;
    }
};
```
